from lxml import etree

def process_soap_request(xml_request):
    # Load DTD for validation
    dtd = etree.DTD('path/to/your.dtd')
    
    # Parse the XML request
    try:
        xml_tree = etree.fromstring(xml_request)
    except etree.XMLSyntaxError as e:
        return f"XML Syntax Error: {str(e)}"

    # Validate against DTD
    if not dtd.validate(xml_tree):
        return f"DTD Validation Error: {dtd.error_log.last_error}"

    # Extract the SOAP body
    try:
        soap_body = xml_tree.find('.//{http://schemas.xmlsoap.org/soap/envelope/}Body')
        if soap_body is not None:
            return etree.tostring(soap_body, pretty_print=True).decode()
        else:
            return "SOAP Body not found"
    except Exception as e:
        return f"Error extracting SOAP Body: {str(e)}"